import React, { useEffect, useRef } from 'react';
import Phaser from 'phaser';

const BallyGamboyGame = () => {
    const gameRef = useRef(null);
    let player;

    useEffect(() => {
        const initializeGame = () => {
            const config = {
                type: Phaser.AUTO,
                width: window.innerWidth,
                height: window.innerHeight,
                scene: {
                    preload: preload,
                    create: create
                },
                physics: {
                    default: 'arcade',
                    arcade: {
                        gravity: { y: 0 },
                        debug: false
                    }
                }
            };

            gameRef.current = new Phaser.Game(config);
        };

        let champID = localStorage.getItem('champID')
        function preload() {
          this.load.image('player', './phaser-resources/images/champions/'+champID+'.png');
          this.load.image('background', './phaser-resources/images/placeholders/gamboy.png');
          this.load.image('upButton', './phaser-resources/images/ui/pad-u.png');
          this.load.image('middleButton', './phaser-resources/images/ui/middle-b.png');
          this.load.image('downButton', './phaser-resources/images/ui/pad-d.png');
          this.load.image('leftButton', './phaser-resources/images/ui/pad-l.png');
          this.load.image('rightButton', './phaser-resources/images/ui/pad-r.png');
      }

        function create() {
            // Create the background sprite and set it to full screen
            const background = this.add.sprite(0, 0, 'background').setOrigin(0).setDisplaySize(window.innerWidth, window.innerHeight);

            // Load player sprite
            player = this.physics.add.sprite(window.innerWidth / 2, window.innerHeight / 2, 'player');

            // Create directional pad buttons
            const buttonSpacing = 20;
            const buttonX = window.innerWidth - 150;
            const buttonY = window.innerHeight - 150;
            this.upButton = this.add.sprite(buttonX, buttonY - buttonSpacing * 2, 'upButton');
            this.downButton = this.add.sprite(buttonX, buttonY + buttonSpacing * 2, 'downButton');
            this.leftButton = this.add.sprite(buttonX - buttonSpacing * 2, buttonY, 'leftButton');
            this.rightButton = this.add.sprite(buttonX + buttonSpacing * 2, buttonY, 'rightButton');

            // Make buttons interactive
            this.upButton.setInteractive();
            this.downButton.setInteractive();
            this.leftButton.setInteractive();
            this.rightButton.setInteractive();

            // Listen for pointer down events on each button
            this.upButton.on('pointerdown', () => movePlayer('up'));
            this.downButton.on('pointerdown', () => movePlayer('down'));
            this.leftButton.on('pointerdown', () => movePlayer('left'));
            this.rightButton.on('pointerdown', () => movePlayer('right'));
        }

        function movePlayer(direction) {
            const speed = 500;
            let destinationX = player.x;
            let destinationY = player.y;

            switch (direction) {
                case 'up':
                    destinationY -= 100;
                    break;
                case 'down':
                    destinationY += 100;
                    break;
                case 'left':
                    destinationX -= 100;
                    break;
                case 'right':
                    destinationX += 100;
                    break;
            }

            // Tween the player sprite to the destination coordinates
            gameRef.current.tweens.add({
                targets: player,
                x: destinationX,
                y: destinationY,
                duration: speed,
                ease: 'Linear',
            });
        }

        initializeGame();

        return () => {
            if (gameRef.current) {
                gameRef.current.destroy(true);
            }
        };
    }, []);

    return <div id="ballygamboy-game-container"></div>;
};

export default BallyGamboyGame;
